import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote: base premiums and processing fee
  it.todo("empty item list → premium 5 G (only processing fee)");
  it.todo("single sword (no modifiers, first contract) → premium with first-insurance surcharge and fee");
  it.todo("single amulet base premium 60 G");
  it.todo("single staff base premium 80 G");
  it.todo("single potion base premium 40 G");

  // Components and building block
  it.todo("2 runes → 50 G base premium (no block)");
  it.todo("3 runes → 60 G base premium (block applies)");
  it.todo("4 runes → 100 G base premium (no block; block requires exactly 3)");
  it.todo("7 runes → 175 G base premium (no block-eligible group)");
  it.todo("2 runes + 1 moonstone → 75 G base premium (different types, no block)");
  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");

  // Item-specific modifiers
  it.todo("cursed item adds 50% surcharge to that item's base premium");
  it.todo("highly enchanted item (enchantment ≥ 5) adds 30% surcharge");
  it.todo("enchantment exactly 5 triggers high-enchantment surcharge");
  it.todo("enchantment 4 does not trigger high-enchantment surcharge");
  it.todo("cursed AND highly enchanted: both surcharges stack");

  // Policy-wide modifiers
  it.todo("long-standing customer (≥ 2 years) gets 20% loyalty discount on policy");
  it.todo("exactly 2 years triggers loyalty discount");
  it.todo("first insurance carries 10% initial assessment surcharge");
  it.todo("follow-up contract carries 15% discount");

  // Multi-item scope
  it.todo("multi-item policy: cursed surcharge applies only to cursed item");

  // Rounding
  it.todo("premium rounded UP to whole G (MHPCO favor)");

  // Integration examples
  it.todo("newcomer with cursed sword → 165 G");
  it.todo("long-standing customer second contract with cursed enchant-7 sword → 160 G");

  // Claim: basic
  it.todo("standard sword damage 500 G → payout 400 G (deductible 100)");
  it.todo("rune damage 200 G → payout 100 G");
  it.todo("damage to item with enchantment ≥ 8: 50% reimbursement then deductible");
  it.todo("damage to dragon-material item: full reimbursement then deductible");
  it.todo("dragon-material + enchantment 9: 50% wins, then deductible");
  it.todo("dragon-material + enchantment 5: full reimbursement (dragon-material clause)");

  // Claim: multi-damage
  it.todo("two damages: deductible applies once per damaged item");

  // Cap exhaustion
  it.todo("cap is 2x insurance sum; payout limited by remaining cap across claims");
  it.todo("block discount does not affect insurance sum");

  // Multiple items same type
  it.todo("policy covers two swords → insurance sum 2000 G");
  it.todo("damages array with more entries of a type than insured → CLI error");

  // Payout rounding
  it.todo("payout rounded DOWN to whole G (MHPCO favor)");

  // Error/edge cases
  it.todo("unknown item type in quote → throws error");
  it.todo("claim references item not in policy → throws error");
  it.todo("claim with negative damage amount → throws error");
});

