const PROCESSING_FEE = 5;

type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: unknown; steps: Step[] };
type QuoteResult = { premium: number };

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const quote = (items: Item[]): QuoteResult => {
  if (items.length === 0) return { premium: PROCESSING_FEE };
  const base = BASE_PREMIUMS[items[0].type];
  const premium = Math.ceil(base * 1.1) + PROCESSING_FEE;
  return { premium };
};

export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
  const results = scenario.steps.map((step) => quote(step.items));
  return { results };
};

