const COMPONENT_TYPES = new Set(["rune"]);
const BLOCK_PREMIUM = 60;
const BLOCK_SIZE = 3;

const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];

const basePremium = (items: Item[]): number => {
  const componentCounts: Record<string, number> = {};
  let total = 0;
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      total += itemBasePremium(item);
    }
  }
  for (const type of Object.keys(componentCounts)) {
    const count = componentCounts[type];
    if (count === BLOCK_SIZE) {
      total += BLOCK_PREMIUM;
    } else {
      total += count * BASE_PREMIUMS[type];
    }
  }
  return total;
};

