const PROCESSING_FEE = 5;

type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: unknown; steps: Step[] };
type QuoteResult = { premium: number };

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const COMPONENT_TYPES = new Set(["rune"]);
const BLOCK_PREMIUM = 60;
const BLOCK_SIZE = 3;

const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];

const basePremium = (items: Item[]): number => {
  const componentCounts: Record<string, number> = {};
  let total = 0;
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      total += itemBasePremium(item);
    }
  }
  for (const type of Object.keys(componentCounts)) {
    const count = componentCounts[type];
    if (count === BLOCK_SIZE) {
      total += BLOCK_PREMIUM;
    } else {
      total += count * BASE_PREMIUMS[type];
    }
  }
  return total;
};

const quote = (items: Item[]): QuoteResult => {
  // first-insurance surcharge 10%: base * 11 / 10
  const premium = Math.ceil((basePremium(items) * 11) / 10 + PROCESSING_FEE);
  return { premium };
};

export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => ({
  results: scenario.steps.map((step) => quote(step.items)),
});

