import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote: base premiums and processing fee
  it("empty item list → premium 5 G (only processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result.results[0]).toEqual({ premium: 5 });
  });
  it("single sword (no modifiers, first contract) → premium 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("single amulet (no modifiers, first contract) → premium 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 71 });
  });
  it("single staff (no modifiers, first contract) → premium 93 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "staff", material: "wood", enchantment: 2, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 93 });
  });
  it("single potion (no modifiers, first contract) → premium 49 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "potion", material: "glass", enchantment: 1, cursed: false }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 49 });
  });

  // Components and building block
  it("2 runes (first contract) → premium 60 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 60 });
  });
  it("3 runes (first contract) → premium 71 G (block applies)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 71 });
  });
  it("4 runes (first contract) → premium 115 G (no block)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("7 runes (first contract) → premium 198 G (no block)", () => {
    const items = Array.from({ length: 7 }, () => ({ type: "rune" }));
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items }],
    });
    expect(result.results[0]).toEqual({ premium: 198 });
  });
  it("2 runes + 1 moonstone (first contract) → premium 88 G (no block)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 88 });
  });
  it("3 runes + 3 moonstones (first contract) → premium 137 G (two blocks)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
            { type: "moonstone" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 137 });
  });

  // Item-specific modifiers
  it("cursed sword (first contract, low enchantment) → premium 170 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
        },
      ],
    });
    expect(result.results[0]).toEqual({ premium: 170 });
  });
  it.todo("highly enchanted item (enchantment ≥ 5) adds 30% surcharge");
  it.todo("enchantment exactly 5 triggers high-enchantment surcharge");
  it.todo("enchantment 4 does not trigger high-enchantment surcharge");
  it.todo("cursed AND highly enchanted: both surcharges stack");

  // Policy-wide modifiers
  it.todo("long-standing customer (≥ 2 years) gets 20% loyalty discount on policy");
  it.todo("exactly 2 years triggers loyalty discount");
  it.todo("first insurance carries 10% initial assessment surcharge");
  it.todo("follow-up contract carries 15% discount");

  // Multi-item scope
  it.todo("multi-item policy: cursed surcharge applies only to cursed item");

  // Rounding
  it.todo("premium rounded UP to whole G (MHPCO favor)");

  // Integration examples
  it.todo("newcomer with cursed sword → 165 G");
  it.todo("long-standing customer second contract with cursed enchant-7 sword → 160 G");

  // Claim: basic
  it.todo("standard sword damage 500 G → payout 400 G (deductible 100)");
  it.todo("rune damage 200 G → payout 100 G");
  it.todo("damage to item with enchantment ≥ 8: 50% reimbursement then deductible");
  it.todo("damage to dragon-material item: full reimbursement then deductible");
  it.todo("dragon-material + enchantment 9: 50% wins, then deductible");
  it.todo("dragon-material + enchantment 5: full reimbursement (dragon-material clause)");

  // Claim: multi-damage
  it.todo("two damages: deductible applies once per damaged item");

  // Cap exhaustion
  it.todo("cap is 2x insurance sum; payout limited by remaining cap across claims");
  it.todo("block discount does not affect insurance sum");

  // Multiple items same type
  it.todo("policy covers two swords → insurance sum 2000 G");
  it.todo("damages array with more entries of a type than insured → CLI error");

  // Payout rounding
  it.todo("payout rounded DOWN to whole G (MHPCO favor)");

  // Error/edge cases
  it.todo("unknown item type in quote → throws error");
  it.todo("claim references item not in policy → throws error");
  it.todo("claim with negative damage amount → throws error");
});

